const inventory = $node["Get Inventory Ledger"].json || [];
const shipments = $node["Get Shipments Ledger"].json || [];
const suppliers = $node["Get Supplier Catalog"].json || [];

const itemsList = Array.isArray(inventory) ? inventory : [inventory];
const shipList = Array.isArray(shipments) ? shipments : [shipments];
const suppList = Array.isArray(suppliers) ? suppliers : [suppliers];

const results = [];

for (const inv of itemsList) {
  const itemName = inv["Item Name"] || inv.ItemName;
  if (!itemName) continue;

  const currentStock = Number(inv["Current Stock"] || 0);
  const dailyUse = Number(inv["Daily Consumption"] || 0);
  const safetyStock = Number(inv["Safety Stock"] || 0);
  const leadTime = Number(inv["Supplier Lead Time"] || 14);
  const currentSupplier = inv["Current Supplier"] || 'Unknown';

  const doc = dailyUse > 0 ? (currentStock / dailyUse).toFixed(1) : 999;

  const reorderPoint = (dailyUse * leadTime) + safetyStock;
  const needsReorder = currentStock <= reorderPoint;

  const itemShipments = shipList.filter(s => (s["Item Name"] || s.ItemName) === itemName);
  let activeShipmentDelay = false;
  let shipmentDetails = "None";

  if (itemShipments.length > 0) {
    const delayShipments = itemShipments.filter(s => s.Status === 'DELAYED');
    if (delayShipments.length > 0) {
      activeShipmentDelay = true;
      shipmentDetails = delayShipments.map(s => `ID: ${s["Shipment ID"] || 'N/A'}, Qty: ${s.Quantity || 0}, Location: ${s.Location || 'Unknown'}, ETA: ${s.ETA || 'N/A'}`).join('; ');
    } else {
      shipmentDetails = itemShipments.map(s => `ID: ${s["Shipment ID"] || 'N/A'}, Qty: ${s.Quantity || 0}, Status: ${s.Status || 'N/A'}`).join('; ');
    }
  }

  const alternatives = suppList
    .filter(s => (s["Item Name"] || s.ItemName) === itemName && s["Supplier Name"] !== currentSupplier)
    .map(s => ({
      supplier: s["Supplier Name"],
      cost: Number(s["Unit Cost"] || 0),
      lead_time: Number(s["Lead Time"] || 14),
      min_order: Number(s["Min Order Qty"] || 0),
      reliability: s["Reliability Rating"] || '90%'
    }));

  const status = (Number(doc) <= leadTime || activeShipmentDelay) ? 'RISK_DETECTED' : 'HEALTHY';

  results.push({
    item_name: itemName,
    current_stock: currentStock,
    daily_consumption: dailyUse,
    safety_stock: safetyStock,
    lead_time_days: leadTime,
    current_supplier: currentSupplier,
    days_of_cover: doc,
    reorder_point: reorderPoint,
    needs_reorder: needsReorder,
    shipment_status: shipmentDetails,
    shipment_delayed: activeShipmentDelay,
    supplier_alternatives: alternatives,
    audit_status: status
  });
}

return results;

